import{_ as o,H as t,f as a,i}from"./chunks/framework.Cvt1eIE0.js";const h=JSON.parse('{"title":"Context","description":"","frontmatter":{"title":"Context","layout":"default"},"headers":[],"relativePath":"context.md","filePath":"context.md"}'),r={name:"context.md"};function l(c,e,s,n,d,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h1><h2 id="project-scope" tabindex="-1">Project scope <a class="header-anchor" href="#project-scope" aria-label="Permalink to &quot;Project scope&quot;">​</a></h2><p><code>tracer</code> is a runtime tracing library for large JS codebases and editors.<br> Primary goals:</p><ul><li>track function/method calls with low overhead;</li><li>track property read/write only when explicitly enabled;</li><li>support scenario-based diagnostics (slices);</li><li>keep production stability as a first priority.</li></ul><h2 id="runtime-strategy" tabindex="-1">Runtime strategy <a class="header-anchor" href="#runtime-strategy" aria-label="Permalink to &quot;Runtime strategy&quot;">​</a></h2><p>The runtime is designed for stability-first integration in complex environments.</p><h3 id="core-principles" tabindex="-1">Core principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core principles&quot;">​</a></h3><ol><li>No automatic property wrapping in <code>observe(...)</code>.</li><li>Property watchers are opt-in and explicit.</li><li>Hybrid object strategy:</li></ol><ul><li>no <code>Proxy</code> by default for object-property observation;</li><li><code>Proxy</code> only for explicit, safe, plain-object cases.</li></ul><ol start="4"><li>Non-full profiles suppress noisy paths to reduce overhead.</li></ol><h2 id="core-api-layers" tabindex="-1">Core API layers <a class="header-anchor" href="#core-api-layers" aria-label="Permalink to &quot;Core API layers&quot;">​</a></h2><h3 id="instrumentation" tabindex="-1">Instrumentation <a class="header-anchor" href="#instrumentation" aria-label="Permalink to &quot;Instrumentation&quot;">​</a></h3><ul><li><code>observe</code>, <code>observePrototype</code>, <code>observeAll</code>, <code>observePrototypeAll</code></li><li><code>createProxyFn</code>, <code>observeConstructor</code></li><li><code>observeProperty</code>, <code>observeAllProperties</code>, <code>observePropertyObject</code></li></ul><h3 id="subscriptions" tabindex="-1">Subscriptions <a class="header-anchor" href="#subscriptions" aria-label="Permalink to &quot;Subscriptions&quot;">​</a></h3><ul><li><code>traceCalls</code>, <code>traceProperties</code>, <code>traceAll</code></li><li>batched variants: <code>trace*Batched</code></li><li>cleanup: <code>untraceCalls</code>, <code>untraceProperties</code>, <code>untraceAll</code></li></ul><h3 id="slice-diagnostics" tabindex="-1">Slice diagnostics <a class="header-anchor" href="#slice-diagnostics" aria-label="Permalink to &quot;Slice diagnostics&quot;">​</a></h3><ul><li>define/enable/disable slice</li><li><code>traceBySlice*</code> flow for scenario windows</li><li>reports focused on slice-contained events</li></ul><h2 id="profiles" tabindex="-1">Profiles <a class="header-anchor" href="#profiles" aria-label="Permalink to &quot;Profiles&quot;">​</a></h2><ul><li><code>minimal</code>: production-safe baseline with lowest tracing overhead.</li><li><code>balanced</code>: default profile, behavior close to <code>minimal</code>.</li><li><code>full</code>: diagnostics mode (calls + properties + context).</li></ul><h2 id="event-model" tabindex="-1">Event model <a class="header-anchor" href="#event-model" aria-label="Permalink to &quot;Event model&quot;">​</a></h2><ul><li>Global stream: <ul><li>function/method call traces</li><li>manually configured property watchers</li></ul></li><li>Slice-scoped stream: <ul><li>subset of traces active only in slice window</li><li>usage accounting for classes/methods/properties only inside slice</li></ul></li></ul><h2 id="integration-context-large-codebase" tabindex="-1">Integration context (large codebase) <a class="header-anchor" href="#integration-context-large-codebase" aria-label="Permalink to &quot;Integration context (large codebase)&quot;">​</a></h2><p>Typical integration pattern for 1M+ LOC projects:</p><ol><li>Build-time injector plugin inserts <code>Tracer.observe(...)</code> / <code>Tracer.observeProperty(...)</code> into selected targets.</li><li>Runtime <code>tracer</code> handles subscriptions, filters, batching, and reports.</li><li>Cache + invalidation on build side reduce reinstrumentation cost.</li><li>Runtime profile (<code>minimal</code>/<code>balanced</code>) keeps overhead acceptable in daily runs.</li></ol><h2 id="behavior-contract-must-stay-stable" tabindex="-1">Behavior contract (must stay stable) <a class="header-anchor" href="#behavior-contract-must-stay-stable" aria-label="Permalink to &quot;Behavior contract (must stay stable)&quot;">​</a></h2><ol><li><code>observe(...)</code> and <code>observePrototype(...)</code> do not auto-wrap arbitrary object properties.</li><li>Manual property watchers stay active globally, regardless of active slices.</li><li>Slice reports (<code>ReportSliceDiff</code>, <code>ReportSliceUsage</code>) aggregate only slice-contained events.</li><li>Slice lifecycle is controlled by start/end predicates and can be exported/imported across teams.</li></ol>',26)])])}const b=o(r,[["render",l]]);export{h as __pageData,b as default};
